"use strict";(self.webpackChunksite=self.webpackChunksite||[]).push([[5796],{8145:e=>{e.exports=JSON.parse('{"lang":"ro","resources":{"landing":{"meta":{"title":"Linguist - Tradu pagini web \xeen mod privat | Extensie de traducere pentru Chrome \u0219i Firefox","description":"Extensie de traducere pentru Chrome \u0219i Firefox, axat\u0103 pe confiden\u021bialitate. Tradu instantaneu pagini web, text selectat, subtitr\u0103ri \u0219i mesaje. Func\u021bioneaz\u0103 offline \u0219i permite integrarea cu servicii de traducere \u0219i API-uri."},"navigation":{"features":{"content":"Func\u021bionalit\u0103\u021bi"},"blog":{"content":"Blog"},"docs":{"content":"Documenta\u021bie"},"github":{"content":"GitHub"}},"install":{"chrome":"Instaleaz\u0103 pentru Chrome","firefox":"Instaleaz\u0103 pentru Firefox"},"sections":{"hero":{"title":"Tradu fluent pagini web","description":"Linguist este un traduc\u0103tor flexibil pentru browser, sus\u021binut de cele mai populare servicii de traducere.\\n\\nTradu pagini web \xeentregi, text selectat, subtitr\u0103ri pe Netflix sau \xeen apeluri video \u0219i mesaje private. Ascult\u0103 traducerile \u0219i salveaz\u0103-le pe cele importante \xeen dic\u021bionarul personal pentru a \xeenv\u0103\u021ba cuvinte noi, chiar \u0219i offline.\\n\\nLinguist este o alternativ\u0103 modern\u0103 la extensiile Google Translate, care pune pe primul loc confiden\u021bialitatea ta. \xcencearc\u0103-l gratuit."},"opensource":{"title":"Open source","content":"Linguist este o extensie de traducere gratuit\u0103 \u0219i <0>open-source</0>. Nu colecteaz\u0103 \u0219i nu vinde datele utilizatorilor.\\n\\nPo\u021bi <1>dona</1> pentru a sus\u021bine Linguist \u0219i a ne ajuta s\u0103 ne men\u021binem independen\u021ba \u0219i calitatea ridicat\u0103.\\n\\nDistribuie Linguist pe re\u021belele sociale pentru a-i ajuta \u0219i pe al\u021bii s\u0103-l descopere."},"support":{"title":"Asisten\u021b\u0103","content":"Dac\u0103 ai \xeentreb\u0103ri, contacteaz\u0103-ne <0/>.\\nDac\u0103 ai g\u0103sit o eroare \u0219i ai un cont de GitHub, te rug\u0103m s\u0103 <1>deschizi un issue</1>."},"createdBy":{"content":"Creat de <0/>."}},"features":{"title":"Func\u021bionalit\u0103\u021bi","items":{"offlineTranslation":{"title":"Traducere offline \u0219i confiden\u021bialitate","content":"Tradu textul direct pe dispozitivul t\u0103u cu ajutorul traduc\u0103torului offline integrat. Textul t\u0103u r\u0103m\xe2ne privat \u0219i nu este trimis pe internet.\\n\\nActiveaz\u0103 aceast\u0103 func\u021bionalitate din pagina de op\u021biuni pentru a p\u0103stra confiden\u021bialitatea traducerilor atunci c\xe2nd lucrezi cu e-mailuri, documente sau mesaje personale.\\n\\nTraduc\u0103torul offline \xee\u021bi permite, de asemenea, s\u0103 traduci pagini f\u0103r\u0103 o conexiune la internet, un avantaj deosebit atunci c\xe2nd c\u0103l\u0103tore\u0219ti."},"fullPageTranslation":{"title":"Tradu pagini web \xeentregi","content":"Traducere rapid\u0103 \u0219i de \xeenalt\u0103 calitate a paginilor complete, din doar c\xe2teva clicuri.\\n\\nFolose\u0219te o comand\u0103 rapid\u0103 de la tastatur\u0103 pentru a traduce instantaneu. Treci cu mouse-ul peste textul tradus pentru a vedea originalul. Tradu chiar \u0219i pagini private, aflate \xeen spatele formularelor de autentificare sau al abonamentelor (paywalls).\\n\\nConfigureaz\u0103 reguli de traducere automat\u0103 \xeen func\u021bie de limba paginii sau de domeniu.\\n\\nLinguist modific\u0103 minim pagina: schimb\u0103 doar nodurile de text \u0219i p\u0103streaz\u0103 aspectul original \u0219i experien\u021ba de navigare.\\n\\nActiveaz\u0103 traducerea \xeen timp real pentru \xeent\xe2lnirile multilingve de pe Zoom, Google Meet \u0219i Microsoft Teams."},"selectedTextTranslation":{"title":"Tradu textul selectat pe orice site","content":"\xcent\xe2lne\u0219ti cuvinte necunoscute \xeen timp ce cite\u0219ti un articol online?\\nSelecteaz\u0103 pur \u0219i simplu textul de pe pagin\u0103 \u0219i apas\u0103 butonul de traducere.\\n\\nAscult\u0103 at\xe2t textul original, c\xe2t \u0219i pe cel tradus, \u0219i salveaz\u0103 traducerile \xeen dic\u021bionar pentru a le revedea mai t\xe2rziu."},"textTranslation":{"title":"Traducere rapid\u0103 de text","content":"Ai nevoie s\u0103 traduci ceva rapid? D\u0103 clic pe pictograma Linguist \u0219i introdu textul.\\n\\nNu este nevoie s\u0103 schimbi filele sau s\u0103 deschizi site-uri de traducere. Tradu direct din browser, folosind serviciul pe care \xeel preferi."},"knowledgeBase":{"title":"Construie\u0219te-\u021bi propria baz\u0103 de cuno\u0219tin\u021be","content":"Fiecare traducere este salvat\u0103 \xeen istoric, iar tu po\u021bi ad\u0103uga intr\u0103rile importante \xeen dic\u021bionarul personal. Caut\u0103 \xeen dic\u021bionar \u0219i \xeen istoricul traducerilor \xeen orice moment.\\n\\nNimic nu se pierde, nici m\u0103car \xeen timpul sesiunilor lungi de cercetare sau de \xeenv\u0103\u021bare.\\n\\nDic\u021bionarul func\u021bioneaz\u0103 offline, ceea ce face ca Linguist s\u0103 fie ideal pentru cei care \xeenva\u021b\u0103 limbi str\u0103ine \u0219i pentru c\u0103l\u0103torii care au nevoie de acces constant la listele lor de cuvinte."},"customTranslators":{"title":"Integreaz\u0103 servicii de traducere \u0219i API-uri","content":"Linguist \xee\u021bi permite s\u0103 alegi ce serviciu de traducere vrei s\u0103 folose\u0219ti.\\n\\nSuport\u0103 furnizori populari de traducere precum Google, Yandex \u0219i Microsoft, av\xe2nd la dispozi\u021bie peste 100 de limbi.\\n\\nDac\u0103 un serviciu de care ai nevoie nu este inclus, \xeel po\u021bi ad\u0103uga ca <0>traduc\u0103tor personalizat</0>.\\n\\nTraduc\u0103torii personaliza\u021bi \xee\u021bi permit s\u0103 integrezi orice sistem de traducere \u2014 de la servicii moderne bazate pe LLM, cum ar fi ChatGPT, DeepL, DeepSeek \u0219i Gemini, p\xe2n\u0103 la traduc\u0103tori locali care ruleaz\u0103 direct pe dispozitivul t\u0103u, precum Ollama sau LibreTranslate."}}},"faq":{"title":"\xcentreb\u0103ri frecvente","items":{"whatIsLinguist":{"title":"Ce este Linguist?","content":"Linguist este o extensie de traducere pentru Chrome \u0219i Firefox, care pune pe primul loc confiden\u021bialitatea.\\n\\n\xce\u021bi permite s\u0103 traduci pagini web \xeentregi, text selectat, subtitr\u0103ri \u0219i mesaje direct \xeen browser, f\u0103r\u0103 a fi nevoie s\u0103 accesezi site-uri externe de traducere."},"whyLinguist":{"title":"De ce s\u0103 folose\u0219ti Linguist?","content":"Exist\u0103 multe extensii de browser care traduc pagini web, iar unele browsere includ chiar traduc\u0103tori integra\u021bi. A\u0219adar, de ce s\u0103 folose\u0219ti Linguist?\\n\\nMajoritatea traduc\u0103torilor integra\u021bi \u0219i a extensiilor de traducere sunt limitate ca flexibilitate. Multe se bazeaz\u0103 pe un singur furnizor de traducere, cum ar fi Google Translate sau Microsoft Bing, \xeen timp ce Firefox ofer\u0103 propriul traduc\u0103tor offline. \xcen cele mai multe cazuri, nu po\u021bi alege serviciul care se potrive\u0219te cel mai bine nevoilor tale.\\n\\nDac\u0103 calitatea traducerii nu este suficient de bun\u0103 pentru ceea ce ai nevoie sau dac\u0103 trimiterea de texte private c\u0103tre servicii ter\u021be nu este o op\u021biune acceptabil\u0103, multe instrumente te las\u0103 f\u0103r\u0103 o alternativ\u0103 viabil\u0103.\\n\\nDe asemenea, multe instrumente se concentreaz\u0103 pe o singur\u0103 sarcin\u0103. Unele traduc pagini \xeentregi, \xeen timp ce altele traduc doar textul selectat.\\n\\n\xcen acela\u0219i timp, unele extensii de traducere sunt construite \xeen principal pentru monetizare. Func\u021bionalit\u0103\u021bi precum istoricul traducerilor sau dic\u021bionarele personale pot necesita un abonament, iar uneori chiar \u0219i op\u021biunile de baz\u0103, cum ar fi tema \xeentunecat\u0103, sunt tratate ca func\u021bionalit\u0103\u021bi premium.\\n\\nLinguist abordeaz\u0103 lucrurile diferit. Este conceput ca un instrument practic de traducere. Po\u021bi alege serviciul de traducere care func\u021bioneaz\u0103 cel mai bine pentru tine, po\u021bi schimba furnizorii sau po\u021bi ad\u0103uga propriii traduc\u0103tori personaliza\u021bi.\\n\\nLinguist aduce, de asemenea, totul \xeentr-un singur loc: tradu pagini web \xeentregi, text selectat, subtitr\u0103ri \u0219i mesaje, p\u0103str\xe2nd \xeen acela\u0219i timp eviden\u021ba traducerilor importante \xeen istoric \u0219i \xeen dic\u021bionarul personal."},"theLinguistLogo":{"title":"De ce logoul Linguist este Turnul Babel?","content":"Logoul Linguist este inspirat de <wiki>Turnul Babel</wiki>, una dintre cele mai vechi pove\u0219ti despre limbaj \u0219i comunicare.\\n\\nConform pove\u0219tii, oamenii vorbeau c\xe2ndva aceea\u0219i limb\u0103 \u0219i au \xeencercat s\u0103 construiasc\u0103 un turn care s\u0103 ajung\u0103 la cer. Turnul nu a fost niciodat\u0103 finalizat, iar omenirea a fost \xeemp\u0103r\u021bit\u0103 \xeen mai multe limbi. De atunci, diferen\u021bele lingvistice au f\u0103cut adesea comunicarea mai dificil\u0103.\\n\\nLinguist a fost creat pentru a ajuta la rezolvarea acestei probleme.\\n\\nTurnul Babel din logo este o reamintire a acelei pove\u0219ti: multe limbi, multe culturi \u0219i efortul uman constant de a ne \xeen\u021belege unii pe al\u021bii. Linguist ajut\u0103 la reducerea acestor bariere, f\u0103c\xe2nd traducerea simpl\u0103, flexibil\u0103 \u0219i accesibil\u0103 direct \xeen browserul t\u0103u.\\n\\nLogoul reflect\u0103, de asemenea, spiritul proiectului. Linguist nu este doar o alt\u0103 interfa\u021b\u0103 pentru \u201eGoogle Translate\u201d. Este construit de oameni c\u0103rora le pas\u0103 de limbi str\u0103ine, de confiden\u021bialitate \u0219i de tehnologia deschis\u0103. Turnul Babel reprezint\u0103 curiozitatea, \xeenv\u0103\u021barea \u0219i ideea c\u0103 diferen\u021bele de limb\u0103 ar trebui s\u0103 \xeei aduc\u0103 pe oameni \xeempreun\u0103, nu s\u0103 \xeei \u021bin\u0103 la distan\u021b\u0103."},"imageTranslation":{"title":"De ce Linguist nu traduce textul din imagini?","content":"Linguist se concentreaz\u0103 pe func\u021bionalit\u0103\u021bi de traducere fiabile \u0219i de \xeenalt\u0103 calitate.\\n\\nAm cercetat diferite abord\u0103ri pentru traducerea textului din imagini. \xcen acest moment, majoritatea solu\u021biilor disponibile nu ofer\u0103 rezultate consecvente, mai ales atunci c\xe2nd ruleaz\u0103 direct \xeen browser \u2014 un aspect important pentru men\u021binerea confiden\u021bialit\u0103\u021bii utilizatorilor.\\n\\nDin acest motiv, Linguist nu include \xeen prezent traducerea imaginilor. Prefer\u0103m s\u0103 nu lans\u0103m func\u021bionalit\u0103\u021bi care nu \xeendeplinesc standardele noastre de calitate.\\n\\nDac\u0103 vom g\u0103si \xeen viitor o modalitate fiabil\u0103 \u0219i care respect\u0103 confiden\u021bialitatea pentru a implementa traducerea imaginilor, vom fi bucuro\u0219i s\u0103 o ad\u0103ug\u0103m."},"howTranslatePages":{"title":"Cum traduce Linguist paginile web?","content":"Linguist poate traduce pagini web \xeentregi din doar c\xe2teva clicuri. Po\u021bi \xeencepe traducerea paginii folosind butonul extensiei sau o comand\u0103 rapid\u0103 de la tastatur\u0103.\\n\\nTextul original r\u0103m\xe2ne \xeentotdeauna accesibil. Treci cu mouse-ul peste textul tradus pentru a vedea originalul."},"offlineTranslation":{"title":"Poate Linguist s\u0103 traduc\u0103 pagini offline?","content":"Da. Linguist include un traduc\u0103tor offline integrat care \xee\u021bi permite s\u0103 traduci text f\u0103r\u0103 a trimite date pe internet.\\n\\nAcest lucru ajut\u0103 la protejarea confiden\u021bialit\u0103\u021bii \u0219i \xee\u021bi permite s\u0103 traduci con\u021binut chiar \u0219i f\u0103r\u0103 o conexiune la internet."},"privacy":{"title":"Linguist respect\u0103 confiden\u021bialitatea?","content":"Da. Linguist este conceput cu g\xe2ndul la confiden\u021bialitate.\\n\\nExtensia nu colecteaz\u0103 \u0219i nu vinde datele utilizatorilor. Atunci c\xe2nd folose\u0219ti <offline-translator>traduc\u0103torul offline</offline-translator>, traducerile sunt procesate \xeen \xeentregime pe dispozitivul t\u0103u."},"supportedBrowsers":{"title":"Ce browsere sunt compatibile cu Linguist?","content":"Linguist este disponibil pentru Chrome \u0219i Firefox. Func\u021bioneaz\u0103, de asemenea, \xeen alte browsere bazate pe Chromium care suport\u0103 extensii Chrome.\\n\\nLinguist func\u021bioneaz\u0103 \u0219i \xeen browserele de Android care suport\u0103 extensii, cum ar fi Firefox pentru Android \u0219i unele browsere bazate pe Chromium."},"selectedText":{"title":"Poate Linguist s\u0103 traduc\u0103 textul selectat?","content":"Da. Selecteaz\u0103 pur \u0219i simplu textul de pe orice pagin\u0103 web \u0219i folose\u0219te butonul de traducere pentru a-l traduce instantaneu.\\n\\nDe asemenea, po\u021bi asculta traducerea \u0219i o po\u021bi salva \xeen dic\u021bionarul personal."},"customTranslators":{"title":"Pot folosi propriul meu serviciu de traducere?","content":"Da. Linguist suport\u0103 <custom-translator>traduc\u0103tori personaliza\u021bi</custom-translator>, care \xee\u021bi permit s\u0103 integrezi servicii de traducere suplimentare.\\n\\nPo\u021bi conecta API-uri externe sau sisteme locale de traducere, cum ar fi <libre-translate>LibreTranslate</libre-translate> sau <ollama>Ollama</ollama>."},"isFree":{"title":"Este Linguist gratuit?","content":"Da. Linguist este complet gratuit \u0219i <linguist>open-source</linguist>.\\n\\nProiectul este sus\u021binut de comunitate, iar tu po\u021bi alege s\u0103 \xeel <donations>sus\u021bii printr-o dona\u021bie</donations>."}}}}},"altVersions":[{"langCode":"ar","langName":"\u0627\u0644\u0639\u0631\u0628\u064a\u0629","url":"https://linguister.io/ar"},{"langCode":"bg","langName":"\u0431\u044a\u043b\u0433\u0430\u0440\u0441\u043a\u0438","url":"https://linguister.io/bg"},{"langCode":"bn","langName":"\u09ac\u09be\u0982\u09b2\u09be","url":"https://linguister.io/bn"},{"langCode":"ca","langName":"catal\xe0","url":"https://linguister.io/ca"},{"langCode":"cs","langName":"\u010de\u0161tina","url":"https://linguister.io/cs"},{"langCode":"da","langName":"dansk","url":"https://linguister.io/da"},{"langCode":"de","langName":"Deutsch","url":"https://linguister.io/de"},{"langCode":"el","langName":"\u0395\u03bb\u03bb\u03b7\u03bd\u03b9\u03ba\u03ac","url":"https://linguister.io/el"},{"langCode":"en","langName":"English","url":"https://linguister.io/"},{"langCode":"es","langName":"espa\xf1ol","url":"https://linguister.io/es"},{"langCode":"fa","langName":"\u0641\u0627\u0631\u0633\u06cc","url":"https://linguister.io/fa"},{"langCode":"fi","langName":"suomi","url":"https://linguister.io/fi"},{"langCode":"fr","langName":"fran\xe7ais","url":"https://linguister.io/fr"},{"langCode":"gu","langName":"\u0a97\u0ac1\u0a9c\u0ab0\u0abe\u0aa4\u0ac0","url":"https://linguister.io/gu"},{"langCode":"he","langName":"\u05e2\u05d1\u05e8\u05d9\u05ea","url":"https://linguister.io/he"},{"langCode":"hi","langName":"\u0939\u093f\u0928\u094d\u0926\u0940","url":"https://linguister.io/hi"},{"langCode":"hu","langName":"magyar","url":"https://linguister.io/hu"},{"langCode":"id","langName":"Indonesia","url":"https://linguister.io/id"},{"langCode":"it","langName":"italiano","url":"https://linguister.io/it"},{"langCode":"ja","langName":"\u65e5\u672c\u8a9e","url":"https://linguister.io/ja"},{"langCode":"jv","langName":"Jawa","url":"https://linguister.io/jv"},{"langCode":"ka","langName":"\u10e5\u10d0\u10e0\u10d7\u10e3\u10da\u10d8","url":"https://linguister.io/ka"},{"langCode":"ko","langName":"\ud55c\uad6d\uc5b4","url":"https://linguister.io/ko"},{"langCode":"mr","langName":"\u092e\u0930\u093e\u0920\u0940","url":"https://linguister.io/mr"},{"langCode":"nb","langName":"norsk bokm\xe5l","url":"https://linguister.io/nb"},{"langCode":"nl","langName":"Nederlands","url":"https://linguister.io/nl"},{"langCode":"pa","langName":"\u0a2a\u0a70\u0a1c\u0a3e\u0a2c\u0a40","url":"https://linguister.io/pa"},{"langCode":"pl","langName":"polski","url":"https://linguister.io/pl"},{"langCode":"pt-BR","langName":"portugu\xeas (Brasil)","url":"https://linguister.io/pt-BR"},{"langCode":"pt-PT","langName":"portugu\xeas europeu","url":"https://linguister.io/pt-PT"},{"langCode":"ro","langName":"rom\xe2n\u0103","url":"https://linguister.io/ro"},{"langCode":"ru","langName":"\u0440\u0443\u0441\u0441\u043a\u0438\u0439","url":"https://linguister.io/ru"},{"langCode":"sl","langName":"sloven\u0161\u010dina","url":"https://linguister.io/sl"},{"langCode":"sr","langName":"\u0441\u0440\u043f\u0441\u043a\u0438","url":"https://linguister.io/sr"},{"langCode":"sv","langName":"svenska","url":"https://linguister.io/sv"},{"langCode":"ta","langName":"\u0ba4\u0bae\u0bbf\u0bb4\u0bcd","url":"https://linguister.io/ta"},{"langCode":"te","langName":"\u0c24\u0c46\u0c32\u0c41\u0c17\u0c41","url":"https://linguister.io/te"},{"langCode":"th","langName":"\u0e44\u0e17\u0e22","url":"https://linguister.io/th"},{"langCode":"tr","langName":"T\xfcrk\xe7e","url":"https://linguister.io/tr"},{"langCode":"uk","langName":"\u0443\u043a\u0440\u0430\u0457\u043d\u0441\u044c\u043a\u0430","url":"https://linguister.io/uk"},{"langCode":"ur","langName":"\u0627\u0631\u062f\u0648","url":"https://linguister.io/ur"},{"langCode":"vi","langName":"Ti\u1ebfng Vi\u1ec7t","url":"https://linguister.io/vi"},{"langCode":"zh-CN","langName":"\u4e2d\u6587\uff08\u4e2d\u56fd\uff09","url":"https://linguister.io/zh-CN"},{"langCode":"zh-TW","langName":"\u4e2d\u6587\uff08\u53f0\u7063\uff09","url":"https://linguister.io/zh-TW"}]}')}}]);